static int
read_val (const char* s, int* vptr, int bits)
{
    char* trash;
    long v;

    if (*s == 'x' || *s == 'X')
	v = strtol (s + 1, &trash, 16);
    else {
	    if (*s == '#')
		    s++;
		v = strtol (s, &trash, 10);
	    }
	    if (bits == 16 && v >= 0x8000 && v <= 0xFFFF)
	        v -= 0x10000;
	    if (v < -(1L << (bits - 1)) || v >= (1L << bits)) {
		fprintf (stderr, "%3d: constant outside of allowed range\n", line_num);
		num_errors++;
		return -1;
    }
    if ((v & (1UL << (bits - 1))) != 0)
	v |= ~((1UL << bits) - 1);
    *vptr = v;
    return 0;
}

